/* Clean SKU scan workflow area */
.scan-panel {
  padding: 0 !important;
  border: 0 !important;
  border-radius: 0 !important;
  background: transparent !important;
  box-shadow: none !important;
  gap: 12px !important;
}

.sku-scan-instruction {
  text-align: center;
  font-size: 17px;
  line-height: 1.35;
  font-weight: 760;
  color: #26384c;
  margin: 4px 0 10px;
}

#scanStatus {
  display: none !important;
}

#scanProgressText.scan-progress-label {
  text-align: center;
  font-size: 15px;
  line-height: 1.3;
  font-weight: 760;
  color: #34475c;
  margin: 8px 0 -2px;
}

.scan-panel .progress-bar {
  height: 10px;
}

