function updateScanInstructionAndProgress(done, total) {
  if (scanInstruction) {
    if (total > 0 && done >= total) {
      scanInstruction.textContent = "Pallet completed";
    } else if (done > 0) {
      scanInstruction.textContent = "Scan the next SKU to continue";
    } else {
      scanInstruction.textContent = "Scan the first SKU to begin";
    }
  }

  if (scanProgressText) {
    const unit = scanState.mode === "quantity" ? "pieces" : "SKU";
    scanProgressText.textContent = done + "/" + total + " " + unit;
  }
}
